#include <stdio.h>
#include <stdlib.h>

int* topo(int N, int** adj, int* indegree) {
    int* topo = (int*)malloc(N * sizeof(int));
    int index = 0;
    for (int i = 0; i < N; i++) {
        if (indegree[i] == 0) {
            topo[index++] = i;
        }
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (adj[topo[i]][j] == 1) {
                indegree[j]--;
                if (indegree[j] == 0) {
                    topo[index++] = j;
                }
            }
        }
    }
    return topo;
}

int main() {
    int N;
    scanf("%d", &N);
    int** adj = (int**)malloc(N * sizeof(int*));
    int* indegree = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        adj[i] = (int*)malloc(N * sizeof(int));
        indegree[i] = 0;
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            scanf("%d", &adj[i][j]);
            if (adj[i][j] == 1) {
                indegree[j]++;
            }
        }
    }
    int* topo = topo(N, adj, indegree);
    for (int i = 0; i < N; i++) {
        printf("%d ", topo[i]);
    }
    return 0;
}

