class Solution {
    public void isCyclic(int N, ArrayList<ArrayList<Integer>> adj) {
        int[] indegree = new int[N];
        for (int i = 0; i < N; i++) {
            for (Integer it : adj.get(i)) {
                indegree[it]++;
            }
        }
        Queue<Integer> q = new LinkedList<Integer>();
        for (int i = 0; i < N; i++) {
            if (indegree[i] == 0) {
                q.add(i);
            }
        }
        int cnt = 0;
        int ind = 0;
        int[] topo = new int[N];
        while (!q.isEmpty()) {
            Integer node = q.poll();
            topo[ind++] = node;
            cnt++;
            for (Integer it : adj.get(node)) {
                indegree[it]--;
                if (indegree[it] == 0) {
                    q.add(it);
                }
            }
        }
        for (int i = 0; i < N; i++) {
            System.out.print(topo[i] + " ");
        }
    }
}

