from collections import defaultdict, deque

def topo(N, adj):
    indegree = [0] * N
    for i in range(N):
        for j in adj[i]:
            indegree[j] += 1
    q = deque([])
    for i in range(N):
        if indegree[i] == 0:
            q.append(i)
    topo = []
    while q:
        node = q.popleft()
        topo.append(node)
        for i in adj[node]:
            indegree[i] -= 1
            if indegree[i] == 0:
                q.append(i)
    return topo

